  private spawnedWindows: Set<AbjectId> = new Set();
  private spawnedWidgets: Set<AbjectId> = new Set();
  // Maps windowId → surfaceId for raiseWindow support
  private windowSurfaces: Map<AbjectId, string> = new Map();
  // Maps objectId → workspaceId for compositor-level workspace filtering
  private objectWorkspaces: Map<AbjectId, string> = new Map();

  // Backward-compat shim: maps old string widget IDs → AbjectIds
  private shimWidgetMap: Map<string, AbjectId> = new Map();
  // Maps old windowId strings → WindowAbject AbjectIds
  private shimWindowMap: Map<string, AbjectId> = new Map();
  // Maps WindowAbject AbjectId → owning Abject
  private windowOwners: Map<AbjectId, AbjectId> = new Map();
  // Maps widget AbjectId → old-style string widget ID (for event translation)
  private widgetIdToShimId: Map<AbjectId, string> = new Map();
  // Maps widget AbjectId → window string ID (for event translation)
  private widgetToWindowShimId: Map<AbjectId, string> = new Map();
  // Maps widget AbjectId → parent WindowAbject AbjectId (for workspace tracing)
  private widgetToWindow: Map<AbjectId, AbjectId> = new Map();

